char *mos6510_disassemble_instruction(uint16_t pc, uint32_t raw) {
    static char buf[160];
    uint8_t prefix = 0;
    uint32_t decode_raw = raw;
    uint8_t b0 = (uint8_t)(raw & 0xFF);
    if (b0 == 0xCB || b0 == 0xDD || b0 == 0xED || b0 == 0xFD) {
        prefix = b0;
        decode_raw = (raw >> 8);
    }

    DecodedInstruction inst = mos6510_decode(decode_raw, prefix, pc);
    const char *mnemonic = "UNKNOWN";
    if (inst.valid) {
        switch (inst.category) {
            case CAT_CONTROL:
                if ((inst.prefix == 0x00 && (inst.opcode == 0xEA))) {
                    mnemonic = "NOP";
                    break;
                }
                if ((inst.prefix == 0x00 && (inst.opcode == 0x4C))) {
                    mnemonic = "JMP abs";
                    break;
                }
                if ((inst.prefix == 0x00 && (inst.opcode == 0x00))) {
                    mnemonic = "BRK";
                    break;
                }
                break;
            case CAT_DATA_TRANSFER:
                if ((inst.prefix == 0x00 && (inst.opcode == 0xA9))) {
                    mnemonic = "LDA #imm";
                    break;
                }
                if ((inst.prefix == 0x00 && (inst.opcode == 0xA5))) {
                    mnemonic = "LDA zp";
                    break;
                }
                if ((inst.prefix == 0x00 && (inst.opcode == 0x85))) {
                    mnemonic = "STA zp";
                    break;
                }
                if ((inst.prefix == 0x00 && (inst.opcode == 0xAA))) {
                    mnemonic = "TAX";
                    break;
                }
                break;
            case CAT_ARITHMETIC:
                if ((inst.prefix == 0x00 && (inst.opcode == 0xE8))) {
                    mnemonic = "INX";
                    break;
                }
                break;
            default:
                break;
        }
    }

    (void)snprintf(buf, sizeof(buf), "PC=%04X %s OP=%02X PREF=%02X LEN=%u CYC=%u r=%u imm=%u addr=%u disp=%d cc=%u",
                   pc,
                   mnemonic,
                   inst.opcode,
                   inst.prefix,
                   (unsigned int)inst.length,
                   (unsigned int)inst.cycles,
                   (unsigned int)inst.r,
                   (unsigned int)inst.imm,
                   (unsigned int)inst.addr,
                   (int)inst.disp,
                   (unsigned int)inst.cc);
    return buf;
}

void mos6510_trace_instruction(CPUState *cpu, DecodedInstruction *inst) {
    (void)cpu;
    if (!inst) return;
    uint32_t raw_for_disasm = inst->raw;
    if (inst->prefix != 0) {
        raw_for_disasm = ((uint32_t)inst->prefix) | (inst->raw << 8);
    }
    printf("[TRACE] %s\n", mos6510_disassemble_instruction(inst->pc, raw_for_disasm));
}

